// ============================================
// VALIDATE INPUT
// ============================================
const allItems = $input.all();

if (!allItems || allItems.length === 0) {
  return [{ json: { _source: 'manual', invoices: [], _validated: true } }];
}

const item = allItems[0];
let body = item.json || {};

// Webhook wraps payload in .body
if (body.body && typeof body.body === 'object') {
  body = body.body;
}

const isManual =
  Object.keys(body).length === 0 ||
  body.manualTriggerPayload !== undefined ||
  body._source === 'manual';

if (isManual) {
  return [{ json: { _source: 'manual', invoices: [], _validated: true } }];
}

const hasBinary = item.binary && Object.keys(item.binary).length > 0;

if (hasBinary && Object.keys(body).length === 0) {
  return [{
    json: { _source: 'webhook_binary', invoices: [], _validated: true, _binary: true },
    binary: item.binary
  }];
}

let invoices = [];
if (Array.isArray(body.invoices)) {
  invoices = body.invoices;
} else if (Array.isArray(body)) {
  invoices = body;
} else if (body.vendor || body.vendor_name || body.amount || body.text) {
  invoices = [body];
}

if (invoices.length === 0 && !hasBinary) {
  return [{
    json: {
      _source: 'webhook',
      invoices: [],
      _validated: false,
      _error: 'No invoices found in request body',
      _receivedKeys: Object.keys(body)
    }
  }];
}

return [{ json: { _source: 'webhook', invoices: invoices, _validated: true } }];

return [{ json: {
  status: 'error',
  code: 400,
  message: $json._error || 'Invalid payload',
  receivedKeys: $json._receivedKeys || []
}}];

// ============================================
// EXTRACT INVOICE DATA
// ============================================
const inputItems = $input.all();
if (!inputItems.length) return [];

const validated = inputItems[0].json || {};
const source = validated._source || 'webhook';
const invoices = validated.invoices || [];

// DEMO MODE
if (source === 'manual') {
  return [{
    json: {
      invoiceId: 'INV-DEMO-001',
      vendor: 'Acme Office Supplies',
      amount: 499.0,
      date: '2026-07-01',
      dueDate: '2026-08-01',
      rawText: 'Invoice INV-DEMO-001\nVendor: Acme Office Supplies\nDate: 2026-07-01\nDue: 2026-08-01\nItem: Office Supplies - Qty 1 @ $499.00\nSubtotal: $460.00\nTax: $39.00\nTotal: $499.00',
      originalFile: 'invoice-499.txt',
      hasImage: false,
      ocrError: null
    }
  }];
}

const results = [];
for (let idx = 0; idx < invoices.length; idx++) {
  const invoice = invoices[idx];
  const rawText = invoice.raw_text || invoice.full_text || invoice.text || '';

  results.push({
    json: {
      invoiceId: invoice.id || invoice.invoice_number || 'INV-' + (idx + 1),
      vendor: invoice.vendor_name || invoice.vendor || 'Unknown Vendor',
      amount: parseFloat(invoice.amount || invoice.total || 0),
      date: invoice.date || invoice.invoice_date || '',
      dueDate: invoice.due_date || invoice.dueDate || '',
      rawText: rawText,
      ocrError: null,
      originalFile: invoice.filename || invoice.file_name || 'json-payload',
      hasImage: Boolean(invoice.image || invoice.image_base64),
      needsOcr: Boolean((invoice.image || invoice.image_base64) && !rawText),
      imageData: invoice.image_base64 || invoice.image || null
    }
  });
}

return results;

return [{ json: {
  status: 'error',
  code: 502,
  message: 'No invoice text available',
  detail: $json.ocrError || 'Provide raw_text or text field, or run OCR service',
  invoiceId: $json.invoiceId
}}];

const invoice = $json;

const system = `You are an accounts payable analyst. Extract structured data from the invoice text below.

Return ONLY a valid JSON object. No markdown fences, no explanation, no prose. Just JSON.

Use this exact schema:
{
  "vendor_name": "string",
  "invoice_number": "string",
  "line_items": [{"description": "string", "quantity": number, "unit_price": number, "total": number}],
  "subtotal": number,
  "tax": number,
  "total": number,
  "due_date": "YYYY-MM-DD",
  "category": "string (e.g. Office Supplies, Software, Consulting)",
  "anomalies": ["string list of concerns, empty if none"],
  "confidence": number between 0 and 1
}`;

return [{ json: {
  _original: invoice,
  model: 'gpt-oss:120b-cloud',
  temperature: 0.1,
  stream: false,
  messages: [
    { role: 'system', content: system },
    { role: 'user', content: invoice.rawText }
  ]
}}];

const httpResp = $input.first().json;
const aiText = httpResp.choices?.[0]?.message?.content ?? '';

let parsed;
try {
  parsed = JSON.parse(aiText);
} catch (e) {
  const fenced = aiText.match(/```(?:json)?\s*\n?([\s\S]*?)\n?```/);
  if (fenced) {
    try { parsed = JSON.parse(fenced[1]); } catch (e2) { parsed = null; }
  }
  if (!parsed) {
    const obj = aiText.match(/\{[\s\S]*\}/);
    if (obj) {
      try { parsed = JSON.parse(obj[0]); } catch (e3) { parsed = { error: 'AI returned non-JSON', raw: aiText.substring(0, 500) }; }
    } else {
      parsed = { error: 'AI returned non-JSON', raw: aiText.substring(0, 500) };
    }
  }
}

// Retrieve original invoice from upstream Build AI Request Body
const upstream = $('Build AI Request Body').all();
const idx = Math.min($itemIndex || 0, upstream.length - 1);
const original = upstream[idx]?.json?._original || {};

const finalAmount = (original.amount && original.amount > 0)
  ? original.amount
  : parseFloat(parsed.total || 0);

return [{ json: {
  ...original,
  invoice: parsed,
  amount: finalAmount
}}];
